+    let steady_state_count = report
+        .resource_telemetry
+        .iter()
+        .filter(|record| record.boundary == TelemetryBoundary::SteadyState)
+        .count();
+    let teardown_count = report
+        .resource_telemetry
+        .iter()
+        .filter(|record| record.boundary == TelemetryBoundary::Teardown)
